
import React, { useEffect, useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { eventService } from '../../services/eventService';
import { productService } from '../../services/productService';
import { ArrowLeft, Printer } from 'lucide-react';
import { useAuth } from '../../contexts/AuthContext';

export const EventSummary: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const { user } = useAuth();
  const [event, setEvent] = useState<any>(null);
  const [products, setProducts] = useState<any[]>([]);
  const [extras, setExtras] = useState<any[]>([]);
  const [ingredients, setIngredients] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (id) {
      loadData(id);
    }
  }, [id]);

  const loadData = async (eventId: string) => {
    try {
      setLoading(true);
      const [eventData, productsData, extrasData] = await Promise.all([
        eventService.getById(eventId),
        eventService.getProducts(eventId),
        eventService.getExtras(eventId)
      ]);

      setEvent(eventData);
      setProducts(productsData || []);
      setExtras(extrasData || []);

      // Calculate aggregated ingredients
      const aggregatedIngredients: any = {};
      
      for (const p of productsData || []) {
        const prodIngredients = await productService.getIngredients(p.product_id);
        if (prodIngredients) {
          prodIngredients.forEach((ing: any) => {
            const key = ing.inventory_id;
            if (!aggregatedIngredients[key]) {
              aggregatedIngredients[key] = {
                name: ing.inventory?.ingredient_name,
                unit: ing.inventory?.unit,
                quantity: 0,
                cost: 0
              };
            }
            aggregatedIngredients[key].quantity += (ing.quantity_required * p.quantity);
            aggregatedIngredients[key].cost += (ing.quantity_required * p.quantity * (ing.inventory?.unit_cost || 0));
          });
        }
      }

      setIngredients(Object.values(aggregatedIngredients));

    } catch (error) {
      console.error("Error loading summary:", error);
    } finally {
      setLoading(false);
    }
  };

  if (loading) return <div>Cargando resumen...</div>;
  if (!event) return <div>Evento no encontrado</div>;

  const totalProductCost = ingredients.reduce((sum, i) => sum + i.cost, 0);
  const totalExtrasCost = extras.reduce((sum, e) => sum + e.cost, 0);
  const totalCost = totalProductCost + totalExtrasCost;
  const totalRevenue = event.total_amount;
  const profit = totalRevenue - totalCost;
  const margin = totalRevenue > 0 ? (profit / totalRevenue) * 100 : 0;

  return (
    <div className="space-y-6 max-w-4xl mx-auto p-8 bg-white shadow-lg my-8 print:shadow-none print:my-0">
      <div className="flex justify-between items-center print:hidden">
        <button
          onClick={() => navigate(`/events/${id}/edit`)}
          className="flex items-center text-gray-600 hover:text-gray-900"
        >
          <ArrowLeft className="h-4 w-4 mr-2" /> Volver
        </button>
        <button
          onClick={() => window.print()}
          className="flex items-center px-4 py-2 bg-brand-orange text-white rounded hover:bg-orange-600"
        >
          <Printer className="h-4 w-4 mr-2" /> Imprimir
        </button>
      </div>

      <div className="border-b pb-6 mb-6">
        <h1 className="text-3xl font-bold text-gray-900">{event.clients?.name} - {event.service_type}</h1>
        <div className="grid grid-cols-2 gap-4 mt-4 text-sm text-gray-600">
          <div>
            <p><span className="font-semibold">Fecha:</span> {new Date(event.event_date).toLocaleDateString()}</p>
            <p><span className="font-semibold">Personas:</span> {event.num_people}</p>
          </div>
          <div className="text-right">
            <p><span className="font-semibold">Estado:</span> {event.status}</p>
            <p><span className="font-semibold">Cliente:</span> {event.clients?.name}</p>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        <div>
          <h2 className="text-lg font-bold mb-4 border-b pb-2">Productos</h2>
          <table className="w-full text-sm">
            <thead>
              <tr className="text-left text-gray-500">
                <th className="pb-2">Producto</th>
                <th className="pb-2 text-right">Cant.</th>
                <th className="pb-2 text-right">Precio Unit.</th>
                <th className="pb-2 text-right">Total</th>
              </tr>
            </thead>
            <tbody className="divide-y">
              {products.map((p, i) => (
                <tr key={i}>
                  <td className="py-2">{p.products?.name}</td>
                  <td className="py-2 text-right">{p.quantity}</td>
                  <td className="py-2 text-right">${p.unit_price.toFixed(2)}</td>
                  <td className="py-2 text-right">${(p.quantity * p.unit_price).toFixed(2)}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>

        <div>
            <h2 className="text-lg font-bold mb-4 border-b pb-2">Extras</h2>
            <table className="w-full text-sm">
                <thead>
                    <tr className="text-left text-gray-500">
                        <th className="pb-2">Descripción</th>
                        <th className="pb-2 text-right">Precio</th>
                    </tr>
                </thead>
                <tbody className="divide-y">
                    {extras.map((e, i) => (
                        <tr key={i}>
                            <td className="py-2">{e.description}</td>
                            <td className="py-2 text-right">${e.price.toFixed(2)}</td>
                        </tr>
                    ))}
                    {extras.length === 0 && (
                        <tr><td colSpan={2} className="py-2 text-gray-500 italic">Sin extras</td></tr>
                    )}
                </tbody>
            </table>
        </div>
      </div>

      <div className="mt-8">
        <h2 className="text-lg font-bold mb-4 border-b pb-2">Lista de Compras (Ingredientes)</h2>
        <div className="bg-gray-50 p-4 rounded">
            <table className="w-full text-sm">
                <thead>
                    <tr className="text-left text-gray-500">
                        <th className="pb-2">Ingrediente</th>
                        <th className="pb-2 text-right">Cantidad Total</th>
                        <th className="pb-2 text-right">Costo Est.</th>
                    </tr>
                </thead>
                <tbody className="divide-y">
                    {ingredients.map((ing, i) => (
                        <tr key={i}>
                            <td className="py-2">{ing.name}</td>
                            <td className="py-2 text-right">{ing.quantity.toFixed(2)} {ing.unit}</td>
                            <td className="py-2 text-right">${ing.cost.toFixed(2)}</td>
                        </tr>
                    ))}
                </tbody>
            </table>
        </div>
      </div>

      <div className="mt-8 border-t pt-6">
        <h2 className="text-lg font-bold mb-4">Resumen Financiero (Interno)</h2>
        <div className="grid grid-cols-2 md:grid-cols-4 gap-4 bg-gray-100 p-4 rounded">
            <div>
                <p className="text-xs text-gray-500">Ingresos Totales</p>
                <p className="text-xl font-bold text-gray-900">${totalRevenue.toFixed(2)}</p>
            </div>
            <div>
                <p className="text-xs text-gray-500">Costos Totales</p>
                <p className="text-xl font-bold text-red-600">${totalCost.toFixed(2)}</p>
            </div>
            <div>
                <p className="text-xs text-gray-500">Utilidad</p>
                <p className="text-xl font-bold text-green-600">${profit.toFixed(2)}</p>
            </div>
            <div>
                <p className="text-xs text-gray-500">Margen</p>
                <p className="text-xl font-bold text-blue-600">{margin.toFixed(1)}%</p>
            </div>
        </div>
      </div>

      <div className="mt-12 text-center text-xs text-gray-400 print:mt-24">
        <p>Generado por EventosApp - {new Date().toLocaleString()}</p>
      </div>
    </div>
  );
};
