import React, { useEffect, useState } from "react";
import { useNavigate, useParams, useSearchParams } from "react-router-dom";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { z } from "zod";
import { eventService } from "../../services/eventService";
import { clientService } from "../../services/clientService";
import { productService } from "../../services/productService";
import { useAuth } from "../../contexts/AuthContext";
import {
  ArrowLeft,
  Save,
  Plus,
  Trash2,
  Calculator,
  FileText,
} from "lucide-react";
import { Database } from "../../types/supabase";

type Client = Database["public"]["Tables"]["clients"]["Row"];
type Product = Database["public"]["Tables"]["products"]["Row"];

const eventSchema = z.object({
  client_id: z.string().min(1, "Selecciona un cliente"),
  event_date: z.string().min(1, "Selecciona una fecha"),
  service_type: z.string().min(2, "Tipo de servicio requerido"),
  num_people: z.coerce.number().min(1, "Mínimo 1 persona"),
  status: z.enum(["quoted", "confirmed", "completed", "cancelled"]),
  discount: z.coerce.number().min(0),
  total_amount: z.coerce.number().min(0),
  notes: z.string().optional(),
});

type EventFormData = z.infer<typeof eventSchema>;

export const EventForm: React.FC = () => {
  const { id } = useParams();
  const [searchParams] = useSearchParams();
  const navigate = useNavigate();
  const { user } = useAuth();

  const [clients, setClients] = useState<Client[]>([]);
  const [products, setProducts] = useState<Product[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Local state for calculator items
  const [selectedProducts, setSelectedProducts] = useState<
    { product_id: string; quantity: number; price: number }[]
  >([]);

  // Local state for extras
  const [extras, setExtras] = useState<
    { description: string; cost: number; price: number }[]
  >([]);

  // State for product unit costs (calculated from ingredients)
  const [productUnitCosts, setProductUnitCosts] = useState<{
    [key: string]: number;
  }>({});

  const {
    register,
    handleSubmit,
    reset,
    watch,
    setValue,
    formState: { errors },
  } = useForm<EventFormData>({
    resolver: zodResolver(eventSchema) as any,
    defaultValues: {
      client_id: "",
      service_type: "",
      event_date:
        searchParams.get("date") || new Date().toISOString().split("T")[0],
      status: "quoted",
      discount: 0,
      total_amount: 0,
      num_people: 100,
    },
  });

  const clientIdParam = searchParams.get("clientId");

  useEffect(() => {
    loadDependencies();
  }, []);

  useEffect(() => {
    if (clientIdParam) {
      setValue("client_id", clientIdParam);
    }
  }, [clientIdParam, clients, setValue]);

  useEffect(() => {
    if (id) {
      loadEvent(id);
    }
  }, [id]);

  // Recalculate total when selected products change
  useEffect(() => {
    const subtotal = selectedProducts.reduce(
      (sum, item) => sum + item.price * item.quantity,
      0,
    );
    const extrasTotal = extras.reduce((sum, item) => sum + item.price, 0);
    const discount = watch("discount") || 0;
    const total =
      subtotal + extrasTotal - (subtotal + extrasTotal) * (discount / 100);
    setValue("total_amount", total);

    // Fetch costs for new products
    selectedProducts.forEach(async (p) => {
      if (p.product_id && productUnitCosts[p.product_id] === undefined) {
        try {
          const ingredients = await productService.getIngredients(p.product_id);
          const cost =
            ingredients?.reduce((sum, ing) => {
              // inventory is an object, need to handle if it's an array or object based on join
              // Supabase join usually returns object for single relation or array for many.
              // inventory is referenced as single inventory item per ingredient row.
              const unitCost = ing.inventory?.unit_cost || 0;
              return sum + ing.quantity_required * unitCost;
            }, 0) || 0;
          setProductUnitCosts((prev) => ({ ...prev, [p.product_id]: cost }));
        } catch (err) {
          console.error(
            "Error fetching ingredients for product",
            p.product_id,
            err,
          );
        }
      }
    });
  }, [selectedProducts, extras, watch("discount")]);

  const loadDependencies = async () => {
    try {
      const [clientsData, productsData] = await Promise.all([
        clientService.getAll(),
        productService.getAll(),
      ]);
      setClients(clientsData);
      setProducts(productsData);
    } catch (err) {
      console.error("Error loading dependencies:", err);
    }
  };

  const loadEvent = async (eventId: string) => {
    try {
      setIsLoading(true);
      const event = await eventService.getById(eventId);
      reset({
        client_id: event?.client_id || "",
        event_date: event?.event_date || "",
        service_type: event?.service_type || "",
        num_people: event?.num_people || 100,
        status: event?.status || "quoted",
        discount: event?.discount || 0,
        total_amount: event?.total_amount || 0,
        notes: event?.notes || "",
      });
      // Load event products
      const eventProducts = await eventService.getProducts(eventId);
      if (eventProducts) {
        setSelectedProducts(
          eventProducts.map((ep) => ({
            product_id: ep.product_id,
            quantity: ep.quantity,
            price: ep.unit_price,
          })),
        );
      }

      // Load event extras
      const eventExtras = await eventService.getExtras(eventId);
      if (eventExtras) {
        setExtras(
          eventExtras.map((e: any) => ({
            description: e.description,
            cost: e.cost,
            price: e.price,
          })),
        );
      }
    } catch (err) {
      console.error("Error loading event:", err);
      setError("Error al cargar el evento");
    } finally {
      setIsLoading(false);
    }
  };

  const handleAddProduct = () => {
    if (products.length > 0) {
      const product = products[0];
      setSelectedProducts([
        ...selectedProducts,
        {
          product_id: product.id,
          quantity: 1,
          price: product.base_price,
        },
      ]);
    }
  };

  const handleRemoveProduct = (index: number) => {
    const newProducts = [...selectedProducts];
    newProducts.splice(index, 1);
    setSelectedProducts(newProducts);
  };

  const handleProductChange = (
    index: number,
    field: "product_id" | "quantity" | "price",
    value: any,
  ) => {
    const newProducts = [...selectedProducts];
    newProducts[index] = { ...newProducts[index], [field]: value };

    if (field === "product_id") {
      const product = products.find((p) => p.id === value);
      if (product) {
        newProducts[index].price = product.base_price;
      }
    }

    setSelectedProducts(newProducts);
  };

  const handleAddExtra = () => {
    setExtras([...extras, { description: "", cost: 0, price: 0 }]);
  };

  const handleRemoveExtra = (index: number) => {
    const newExtras = [...extras];
    newExtras.splice(index, 1);
    setExtras(newExtras);
  };

  const handleExtraChange = (
    index: number,
    field: "description" | "cost" | "price",
    value: any,
  ) => {
    const newExtras = [...extras];
    newExtras[index] = { ...newExtras[index], [field]: value };
    setExtras(newExtras);
  };

  const onSubmit = async (data: EventFormData) => {
    if (!user) return;

    setIsLoading(true);
    setError(null);

    try {
      let eventId = id;

      if (id) {
        await eventService.update(id, {
          ...data,
        });
      } else {
        const newEvent = await eventService.create({
          ...data,
          user_id: user.id,
        });
        eventId = newEvent.id;
      }

      if (eventId) {
        const productsToSave = selectedProducts.map((p) => ({
          productId: p.product_id,
          quantity: p.quantity,
          unitPrice: p.price,
        }));

        await eventService.updateProducts(eventId, productsToSave);
        await eventService.updateExtras(eventId, extras);
      }

      navigate("/calendar");
    } catch (err: any) {
      console.error("Error saving event:", err);
      setError(err.message || "Error al guardar el evento");
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div className="flex items-center">
          <button
            onClick={() => navigate("/calendar")}
            className="mr-4 p-2 rounded-full hover:bg-gray-100 text-gray-500"
          >
            <ArrowLeft className="h-5 w-5" />
          </button>
          <h1 className="text-2xl font-bold text-gray-900">
            {id ? "Editar Evento" : "Nuevo Evento"}
          </h1>
        </div>
        {id && (
          <button
            onClick={() => navigate(`/events/${id}/summary`)}
            className="inline-flex items-center px-4 py-2 border border-transparent rounded-md shadow-sm text-sm font-medium text-white bg-blue-600 hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-500"
          >
            <FileText className="-ml-1 mr-2 h-5 w-5" />
            Ver Resumen
          </button>
        )}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Formulario Principal */}
        <div className="lg:col-span-2 bg-white shadow px-4 py-5 sm:rounded-lg sm:p-6">
          <form
            id="event-form"
            onSubmit={handleSubmit(onSubmit)}
            className="space-y-6"
          >
            {error && (
              <div className="bg-red-50 border-l-4 border-red-400 p-4">
                <div className="flex">
                  <div className="ml-3">
                    <p className="text-sm text-red-700">{error}</p>
                  </div>
                </div>
              </div>
            )}

            <div className="grid grid-cols-1 gap-y-6 gap-x-4 sm:grid-cols-6">
              <div className="sm:col-span-3">
                <label
                  htmlFor="client_id"
                  className="block text-sm font-medium text-gray-700"
                >
                  Cliente *
                </label>
                <div className="mt-1">
                  <select
                    {...register("client_id")}
                    className="shadow-sm focus:ring-brand-orange focus:border-brand-orange block w-full sm:text-sm border-gray-300 rounded-md p-2 border"
                  >
                    <option value="">Seleccionar cliente</option>
                    {clients.map((client) => (
                      <option key={client.id} value={client.id}>
                        {client.name}
                      </option>
                    ))}
                  </select>
                  {errors.client_id && (
                    <p className="mt-2 text-sm text-red-600">
                      {errors.client_id.message}
                    </p>
                  )}
                  {watch("client_id") && (
                    <div className="mt-2 text-xs text-gray-500 bg-gray-50 p-2 rounded border">
                      {(() => {
                        const selectedClient = clients.find(
                          (c) => c.id === watch("client_id"),
                        );
                        if (selectedClient) {
                          return (
                            <>
                              <span className="font-medium">
                                Historial del Cliente:
                              </span>{" "}
                              {selectedClient.total_events} eventos realizados,
                              Total gastado: $
                              {selectedClient.total_spent?.toFixed(2) || "0.00"}
                            </>
                          );
                        }
                        return null;
                      })()}
                    </div>
                  )}
                </div>
              </div>

              <div className="sm:col-span-3">
                <label
                  htmlFor="event_date"
                  className="block text-sm font-medium text-gray-700"
                >
                  Fecha del Evento *
                </label>
                <div className="mt-1">
                  <input
                    type="date"
                    {...register("event_date")}
                    className="shadow-sm focus:ring-brand-orange focus:border-brand-orange block w-full sm:text-sm border-gray-300 rounded-md p-2 border"
                  />
                  {errors.event_date && (
                    <p className="mt-2 text-sm text-red-600">
                      {errors.event_date.message}
                    </p>
                  )}
                </div>
              </div>

              <div className="sm:col-span-3">
                <label
                  htmlFor="service_type"
                  className="block text-sm font-medium text-gray-700"
                >
                  Tipo de Servicio *
                </label>
                <div className="mt-1">
                  <input
                    type="text"
                    {...register("service_type")}
                    placeholder="Ej. Barra de Churros"
                    className="shadow-sm focus:ring-brand-orange focus:border-brand-orange block w-full sm:text-sm border-gray-300 rounded-md p-2 border"
                  />
                  {errors.service_type && (
                    <p className="mt-2 text-sm text-red-600">
                      {errors.service_type.message}
                    </p>
                  )}
                </div>
              </div>

              <div className="sm:col-span-3">
                <label
                  htmlFor="num_people"
                  className="block text-sm font-medium text-gray-700"
                >
                  Número de Personas *
                </label>
                <div className="mt-1">
                  <input
                    type="number"
                    {...register("num_people")}
                    className="shadow-sm focus:ring-brand-orange focus:border-brand-orange block w-full sm:text-sm border-gray-300 rounded-md p-2 border"
                  />
                  {errors.num_people && (
                    <p className="mt-2 text-sm text-red-600">
                      {errors.num_people.message}
                    </p>
                  )}
                </div>
              </div>

              <div className="sm:col-span-3">
                <label
                  htmlFor="status"
                  className="block text-sm font-medium text-gray-700"
                >
                  Estado *
                </label>
                <div className="mt-1">
                  <select
                    {...register("status")}
                    className="shadow-sm focus:ring-brand-orange focus:border-brand-orange block w-full sm:text-sm border-gray-300 rounded-md p-2 border"
                  >
                    <option value="quoted">Cotizado</option>
                    <option value="confirmed">Confirmado</option>
                    <option value="completed">Completado</option>
                    <option value="cancelled">Cancelado</option>
                  </select>
                </div>
              </div>

              <div className="sm:col-span-6">
                <label
                  htmlFor="notes"
                  className="block text-sm font-medium text-gray-700"
                >
                  Notas
                </label>
                <div className="mt-1">
                  <textarea
                    {...register("notes")}
                    rows={3}
                    className="shadow-sm focus:ring-brand-orange focus:border-brand-orange block w-full sm:text-sm border-gray-300 rounded-md p-2 border"
                  />
                </div>
              </div>
            </div>
          </form>
        </div>

        {/* Calculadora */}
        <div className="lg:col-span-1 bg-white shadow px-4 py-5 sm:rounded-lg sm:p-6 flex flex-col">
          <h3 className="text-lg leading-6 font-medium text-gray-900 mb-4 flex items-center">
            <Calculator className="h-5 w-5 mr-2 text-brand-orange" />
            Calculadora de Costos
          </h3>

          <div className="flex-1 overflow-y-auto mb-4 space-y-3">
            <h4 className="text-sm font-medium text-gray-700">Productos</h4>
            {selectedProducts.map((item, index) => (
              <div
                key={index}
                className="bg-gray-50 p-3 rounded-md relative group"
              >
                <button
                  type="button"
                  onClick={() => handleRemoveProduct(index)}
                  className="absolute top-1 right-1 text-gray-400 hover:text-red-500"
                >
                  <Trash2 className="h-4 w-4" />
                </button>
                <div className="mb-2 pr-6">
                  <select
                    value={item.product_id}
                    onChange={(e) =>
                      handleProductChange(index, "product_id", e.target.value)
                    }
                    className="block w-full text-sm border-gray-300 rounded-md shadow-sm focus:ring-brand-orange focus:border-brand-orange"
                  >
                    <option value="">Seleccionar producto</option>
                    {products.map((p) => (
                      <option key={p.id} value={p.id}>
                        {p.name}
                      </option>
                    ))}
                  </select>
                </div>
                <div className="flex gap-2">
                  <div className="w-1/2">
                    <label className="text-xs text-gray-500">Cant.</label>
                    <input
                      type="number"
                      value={item.quantity}
                      onChange={(e) =>
                        handleProductChange(
                          index,
                          "quantity",
                          Number(e.target.value),
                        )
                      }
                      className="block w-full text-sm border-gray-300 rounded-md shadow-sm focus:ring-brand-orange focus:border-brand-orange"
                    />
                  </div>
                  <div className="w-1/2">
                    <label className="text-xs text-gray-500">Precio</label>
                    <input
                      type="number"
                      value={item.price}
                      onChange={(e) =>
                        handleProductChange(
                          index,
                          "price",
                          Number(e.target.value),
                        )
                      }
                      className="block w-full text-sm border-gray-300 rounded-md shadow-sm focus:ring-brand-orange focus:border-brand-orange"
                    />
                  </div>
                </div>
                {item.product_id &&
                  productUnitCosts[item.product_id] !== undefined && (
                    <div className="mt-1 text-xs text-gray-400">
                      Costo est. unitario: $
                      {productUnitCosts[item.product_id].toFixed(2)}
                    </div>
                  )}
              </div>
            ))}

            <button
              type="button"
              onClick={handleAddProduct}
              className="w-full flex items-center justify-center px-4 py-2 border border-gray-300 shadow-sm text-sm font-medium rounded-md text-gray-700 bg-white hover:bg-gray-50"
            >
              <Plus className="h-4 w-4 mr-2" /> Agregar Producto
            </button>

            <div className="border-t pt-4 mt-4">
              <h4 className="text-sm font-medium text-gray-700 mb-2">
                Extras (Transporte, Personal, etc.)
              </h4>
              {extras.map((item, index) => (
                <div
                  key={`extra-${index}`}
                  className="bg-gray-50 p-3 rounded-md relative group mb-3"
                >
                  <button
                    type="button"
                    onClick={() => handleRemoveExtra(index)}
                    className="absolute top-1 right-1 text-gray-400 hover:text-red-500"
                  >
                    <Trash2 className="h-4 w-4" />
                  </button>
                  <div className="mb-2 pr-6">
                    <input
                      type="text"
                      placeholder="Descripción"
                      value={item.description}
                      onChange={(e) =>
                        handleExtraChange(index, "description", e.target.value)
                      }
                      className="block w-full text-sm border-gray-300 rounded-md shadow-sm focus:ring-brand-orange focus:border-brand-orange"
                    />
                  </div>
                  <div className="flex gap-2">
                    <div className="w-1/2">
                      <label className="text-xs text-gray-500">
                        Costo (Gasto)
                      </label>
                      <input
                        type="number"
                        value={item.cost}
                        onChange={(e) =>
                          handleExtraChange(
                            index,
                            "cost",
                            Number(e.target.value),
                          )
                        }
                        className="block w-full text-sm border-gray-300 rounded-md shadow-sm focus:ring-brand-orange focus:border-brand-orange"
                      />
                    </div>
                    <div className="w-1/2">
                      <label className="text-xs text-gray-500">
                        Precio (Cobro)
                      </label>
                      <input
                        type="number"
                        value={item.price}
                        onChange={(e) =>
                          handleExtraChange(
                            index,
                            "price",
                            Number(e.target.value),
                          )
                        }
                        className="block w-full text-sm border-gray-300 rounded-md shadow-sm focus:ring-brand-orange focus:border-brand-orange"
                      />
                    </div>
                  </div>
                </div>
              ))}
              <button
                type="button"
                onClick={handleAddExtra}
                className="w-full flex items-center justify-center px-4 py-2 border border-gray-300 shadow-sm text-sm font-medium rounded-md text-gray-700 bg-white hover:bg-gray-50"
              >
                <Plus className="h-4 w-4 mr-2" /> Agregar Extra
              </button>
            </div>
          </div>

          <div className="border-t pt-4 space-y-2">
            <div className="flex justify-between items-center">
              <span className="text-sm text-gray-500">Subtotal Productos</span>
              <span className="text-sm font-medium text-gray-900">
                $
                {selectedProducts
                  .reduce((sum, item) => sum + item.price * item.quantity, 0)
                  .toFixed(2)}
              </span>
            </div>
            <div className="flex justify-between items-center">
              <span className="text-sm text-gray-500">Subtotal Extras</span>
              <span className="text-sm font-medium text-gray-900">
                ${extras.reduce((sum, item) => sum + item.price, 0).toFixed(2)}
              </span>
            </div>
            <div className="flex justify-between items-center">
              <span className="text-sm text-gray-500">Descuento (%)</span>
              <input
                type="number"
                {...register("discount")}
                className="w-16 text-right text-sm border-gray-300 rounded-md shadow-sm focus:ring-brand-orange focus:border-brand-orange p-1"
              />
            </div>
            <div className="flex justify-between items-center pt-2 border-t">
              <span className="text-base font-bold text-gray-900">
                Total Venta
              </span>
              <span className="text-xl font-bold text-brand-orange">
                ${watch("total_amount").toFixed(2)}
              </span>
            </div>

            {/* Resumen Financiero */}
            <div className="mt-4 pt-4 border-t border-gray-200">
              <h4 className="text-xs font-semibold text-gray-500 uppercase tracking-wider mb-2">
                Resumen Financiero
              </h4>
              <div className="grid grid-cols-2 gap-2 text-sm">
                <div className="text-gray-500">Costo Ingredientes:</div>
                <div className="text-right font-medium">
                  $
                  {selectedProducts
                    .reduce(
                      (sum, p) =>
                        sum +
                        (productUnitCosts[p.product_id] || 0) * p.quantity,
                      0,
                    )
                    .toFixed(2)}
                </div>
                <div className="text-gray-500">Costo Extras:</div>
                <div className="text-right font-medium">
                  ${extras.reduce((sum, e) => sum + e.cost, 0).toFixed(2)}
                </div>
                <div className="text-gray-900 font-bold border-t pt-1 mt-1">
                  Costo Total:
                </div>
                <div className="text-right font-bold border-t pt-1 mt-1">
                  $
                  {(
                    selectedProducts.reduce(
                      (sum, p) =>
                        sum +
                        (productUnitCosts[p.product_id] || 0) * p.quantity,
                      0,
                    ) + extras.reduce((sum, e) => sum + e.cost, 0)
                  ).toFixed(2)}
                </div>

                <div className="text-green-600 font-bold mt-2">Utilidad:</div>
                <div className="text-right font-bold text-green-600 mt-2">
                  $
                  {(
                    watch("total_amount") -
                    (selectedProducts.reduce(
                      (sum, p) =>
                        sum +
                        (productUnitCosts[p.product_id] || 0) * p.quantity,
                      0,
                    ) +
                      extras.reduce((sum, e) => sum + e.cost, 0))
                  ).toFixed(2)}
                </div>
                <div className="text-gray-500 text-xs">Margen:</div>
                <div className="text-right text-xs text-gray-500">
                  {watch("total_amount") > 0
                    ? (
                        ((watch("total_amount") -
                          (selectedProducts.reduce(
                            (sum, p) =>
                              sum +
                              (productUnitCosts[p.product_id] || 0) *
                                p.quantity,
                            0,
                          ) +
                            extras.reduce((sum, e) => sum + e.cost, 0))) /
                          watch("total_amount")) *
                        100
                      ).toFixed(1)
                    : 0}
                  %
                </div>
              </div>
            </div>
          </div>

          <div className="mt-6">
            <button
              type="submit"
              form="event-form"
              disabled={isLoading}
              className="w-full flex justify-center py-2 px-4 border border-transparent rounded-md shadow-sm text-sm font-medium text-white bg-brand-orange hover:bg-orange-600 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-brand-orange disabled:opacity-50"
            >
              <Save className="h-5 w-5 mr-2" />
              {isLoading ? "Guardando..." : "Guardar Evento"}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};
