import React, { useEffect, useState } from 'react';
import { useParams, Link, useNavigate } from 'react-router-dom';
import { clientService } from '../../services/clientService';
import { Database } from '../../types/supabase';
import { ArrowLeft, Edit, Calendar, DollarSign, MapPin, Phone, Mail, FileText } from 'lucide-react';
import { format } from 'date-fns';
import { es } from 'date-fns/locale';

type Client = Database['public']['Tables']['clients']['Row'];

export const ClientDetails: React.FC = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const [client, setClient] = useState<Client | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (id) {
      loadClient(id);
    }
  }, [id]);

  const loadClient = async (clientId: string) => {
    try {
      setLoading(true);
      const data = await clientService.getById(clientId);
      setClient(data);
    } catch (error) {
      console.error('Error fetching client:', error);
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return <div className="text-center p-8">Cargando detalles...</div>;
  }

  if (!client) {
    return <div className="text-center p-8">Cliente no encontrado</div>;
  }

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div className="flex items-center">
          <button
            onClick={() => navigate('/clients')}
            className="mr-4 p-2 rounded-full hover:bg-gray-100 text-gray-500"
          >
            <ArrowLeft className="h-5 w-5" />
          </button>
          <h1 className="text-2xl font-bold text-gray-900">{client.name}</h1>
        </div>
        <Link
          to={`/clients/${client.id}/edit`}
          className="inline-flex items-center px-4 py-2 border border-gray-300 rounded-md shadow-sm text-sm font-medium text-gray-700 bg-white hover:bg-gray-50"
        >
          <Edit className="h-5 w-5 mr-2" />
          Editar
        </Link>
      </div>

      <div className="bg-white shadow overflow-hidden sm:rounded-lg">
        <div className="px-4 py-5 sm:px-6">
          <h3 className="text-lg leading-6 font-medium text-gray-900">
            Información del Cliente
          </h3>
          <p className="mt-1 max-w-2xl text-sm text-gray-500">
            Detalles personales y de contacto.
          </p>
        </div>
        <div className="border-t border-gray-200 px-4 py-5 sm:px-6">
          <dl className="grid grid-cols-1 gap-x-4 gap-y-8 sm:grid-cols-2">
            <div className="sm:col-span-1">
              <dt className="text-sm font-medium text-gray-500 flex items-center">
                <Phone className="h-4 w-4 mr-2" /> Teléfono
              </dt>
              <dd className="mt-1 text-sm text-gray-900">{client.phone}</dd>
            </div>
            <div className="sm:col-span-1">
              <dt className="text-sm font-medium text-gray-500 flex items-center">
                <Mail className="h-4 w-4 mr-2" /> Email
              </dt>
              <dd className="mt-1 text-sm text-gray-900">{client.email || 'No registrado'}</dd>
            </div>
            <div className="sm:col-span-1">
              <dt className="text-sm font-medium text-gray-500 flex items-center">
                <MapPin className="h-4 w-4 mr-2" /> Dirección
              </dt>
              <dd className="mt-1 text-sm text-gray-900">{client.address || 'No registrada'}</dd>
            </div>
            <div className="sm:col-span-1">
              <dt className="text-sm font-medium text-gray-500 flex items-center">
                <DollarSign className="h-4 w-4 mr-2" /> Total Gastado
              </dt>
              <dd className="mt-1 text-sm text-gray-900 font-semibold text-green-600">
                ${client.total_spent.toFixed(2)}
              </dd>
            </div>
            <div className="sm:col-span-2">
              <dt className="text-sm font-medium text-gray-500 flex items-center">
                <FileText className="h-4 w-4 mr-2" /> Notas
              </dt>
              <dd className="mt-1 text-sm text-gray-900">
                {client.notes || 'Sin notas adicionales.'}
              </dd>
            </div>
          </dl>
        </div>
      </div>

      <div className="bg-white shadow overflow-hidden sm:rounded-lg">
        <div className="px-4 py-5 sm:px-6 flex justify-between items-center">
          <div>
            <h3 className="text-lg leading-6 font-medium text-gray-900">
              Historial de Eventos
            </h3>
            <p className="mt-1 max-w-2xl text-sm text-gray-500">
              Lista de eventos pasados y futuros.
            </p>
          </div>
          <Link
            to={`/events/new?clientId=${client.id}`}
            className="inline-flex items-center px-3 py-1.5 border border-transparent text-xs font-medium rounded-md text-white bg-brand-orange hover:bg-orange-600"
          >
            Nuevo Evento
          </Link>
        </div>
        <div className="border-t border-gray-200">
          <div className="px-4 py-5 sm:p-6 text-center text-gray-500">
            <Calendar className="mx-auto h-12 w-12 text-gray-400" />
            <p className="mt-2">No hay eventos registrados para este cliente.</p>
          </div>
        </div>
      </div>
    </div>
  );
};
