import React, { useState } from 'react';
import { useAuth } from '../contexts/AuthContext';
import { systemService } from '../services/systemService';
import { User, CreditCard, Shield, Database, RefreshCw } from 'lucide-react';

export const Settings: React.FC = () => {
  const { user, profile } = useAuth();
  const [fixing, setFixing] = useState(false);
  const [fixMessage, setFixMessage] = useState<string | null>(null);

  const handleFixData = async () => {
    if (!window.confirm('This will assign all existing data to your current user. Continue?')) return;
    
    setFixing(true);
    setFixMessage(null);
    try {
      await systemService.claimData();
      setFixMessage('Data successfully recovered! Reload the page.');
      setTimeout(() => window.location.reload(), 1500);
    } catch (err) {
      console.error(err);
      setFixMessage('Error recovering data. Please try again.');
    } finally {
      setFixing(false);
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <h1 className="text-2xl font-bold text-gray-900">Settings</h1>
      </div>

      <div className="bg-white shadow overflow-hidden sm:rounded-lg">
        <div className="px-4 py-5 sm:px-6">
          <h3 className="text-lg leading-6 font-medium text-gray-900">User Profile</h3>
          <p className="mt-1 max-w-2xl text-sm text-gray-500">Account and subscription details.</p>
        </div>
        <div className="border-t border-gray-200 px-4 py-5 sm:p-0">
          <dl className="sm:divide-y sm:divide-gray-200">
            <div className="py-4 sm:py-5 sm:grid sm:grid-cols-3 sm:gap-4 sm:px-6">
              <dt className="text-sm font-medium text-gray-500 flex items-center">
                <User className="h-4 w-4 mr-2" /> Nombre
              </dt>
              <dd className="mt-1 text-sm text-gray-900 sm:mt-0 sm:col-span-2">
                {profile?.name}
              </dd>
            </div>
            <div className="py-4 sm:py-5 sm:grid sm:grid-cols-3 sm:gap-4 sm:px-6">
              <dt className="text-sm font-medium text-gray-500 flex items-center">
                <Shield className="h-4 w-4 mr-2" /> Email
              </dt>
              <dd className="mt-1 text-sm text-gray-900 sm:mt-0 sm:col-span-2">
                {profile?.email}
              </dd>
            </div>
            <div className="py-4 sm:py-5 sm:grid sm:grid-cols-3 sm:gap-4 sm:px-6">
              <dt className="text-sm font-medium text-gray-500 flex items-center">
                <CreditCard className="h-4 w-4 mr-2" /> Plan Actual
              </dt>
              <dd className="mt-1 text-sm text-gray-900 sm:mt-0 sm:col-span-2">
                <span className={`px-2 inline-flex text-xs leading-5 font-semibold rounded-full ${
                  profile?.plan === 'premium' ? 'bg-green-100 text-green-800' : 'bg-gray-100 text-gray-800'
                }`}>
                  {profile?.plan === 'premium' ? 'Premium' : 'Básico'}
                </span>
                {profile?.plan === 'basic' && (
                  <p className="mt-2 text-xs text-gray-500">
                    El plan básico permite hasta 10 clientes y 20 eventos mensuales.
                  </p>
                )}
              </dd>
            </div>
          </dl>
        </div>
      </div>
      
      {/* Future: Subscription Management */}
      <div className="bg-white shadow sm:rounded-lg">
        <div className="px-4 py-5 sm:p-6">
          <h3 className="text-lg leading-6 font-medium text-gray-900 flex items-center">
            <Database className="h-5 w-5 mr-2 text-brand-orange" />
            Recuperación de Datos
          </h3>
          <div className="mt-2 max-w-xl text-sm text-gray-500">
            <p>
              Si no ves tus clientes, eventos o productos, usa este botón para reasignar todos los datos existentes a tu cuenta actual.
              Útil después de problemas de conexión o reinicio de sesión.
            </p>
          </div>
          <div className="mt-5">
            <button
              type="button"
              onClick={handleFixData}
              disabled={fixing}
              className="inline-flex items-center justify-center px-4 py-2 border border-transparent shadow-sm font-medium rounded-md text-white bg-brand-orange hover:bg-orange-600 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-brand-orange sm:text-sm disabled:opacity-50"
            >
              {fixing ? (
                <>
                  <RefreshCw className="h-4 w-4 mr-2 animate-spin" /> Recuperando...
                </>
              ) : (
                'Recuperar Mis Datos'
              )}
            </button>
            {fixMessage && (
              <p className={`mt-2 text-sm ${fixMessage.includes('Error') ? 'text-red-600' : 'text-green-600'}`}>
                {fixMessage}
              </p>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};
