import React, { useEffect, useState } from "react";
import { supabase } from "../lib/supabase";
import { systemService } from "../services/systemService";
import {
  ClipboardCopy,
  RefreshCw,
  ShieldAlert,
  CheckCircle,
  XCircle,
  Database,
  Terminal,
} from "lucide-react";

export const Debug: React.FC = () => {
  const [status, setStatus] = useState<any>({ loading: true });
  const [isFixing, setIsFixing] = useState(false);
  const [fixResult, setFixResult] = useState<{
    success: boolean;
    message: string;
  } | null>(null);

  const repairScript = `
-- FINAL REPAIR SCRIPT: Fixes RLS, Permissions, and Triggers for ALL tables
-- Run this in Supabase SQL Editor to restore full functionality

-- 1. Enable RLS on ALL tables
ALTER TABLE IF EXISTS users ENABLE ROW LEVEL SECURITY;
ALTER TABLE IF EXISTS clients ENABLE ROW LEVEL SECURITY;
ALTER TABLE IF EXISTS events ENABLE ROW LEVEL SECURITY;
ALTER TABLE IF EXISTS products ENABLE ROW LEVEL SECURITY;
ALTER TABLE IF EXISTS inventory ENABLE ROW LEVEL SECURITY;
ALTER TABLE IF EXISTS event_products ENABLE ROW LEVEL SECURITY;
ALTER TABLE IF EXISTS event_extras ENABLE ROW LEVEL SECURITY;
ALTER TABLE IF EXISTS product_ingredients ENABLE ROW LEVEL SECURITY;

-- 2. Drop ALL existing policies to ensure a clean slate (avoids conflicts)
DROP POLICY IF EXISTS "Usuarios pueden ver solo sus propios datos" ON users;
DROP POLICY IF EXISTS "Users can view their own profile" ON users;
DROP POLICY IF EXISTS "Users can update their own profile" ON users;

DROP POLICY IF EXISTS "Usuarios pueden gestionar sus clientes" ON clients;
DROP POLICY IF EXISTS "Users can view their own clients" ON clients;
DROP POLICY IF EXISTS "Users can insert their own clients" ON clients;
DROP POLICY IF EXISTS "Users can update their own clients" ON clients;
DROP POLICY IF EXISTS "Users can delete their own clients" ON clients;

DROP POLICY IF EXISTS "Usuarios pueden gestionar sus eventos" ON events;
DROP POLICY IF EXISTS "Users can view their own events" ON events;
DROP POLICY IF EXISTS "Users can insert their own events" ON events;
DROP POLICY IF EXISTS "Users can update their own events" ON events;
DROP POLICY IF EXISTS "Users can delete their own events" ON events;

DROP POLICY IF EXISTS "Usuarios pueden gestionar sus productos" ON products;
DROP POLICY IF EXISTS "Users can view their own products" ON products;
DROP POLICY IF EXISTS "Users can insert their own products" ON products;
DROP POLICY IF EXISTS "Users can update their own products" ON products;
DROP POLICY IF EXISTS "Users can delete their own products" ON products;

DROP POLICY IF EXISTS "Usuarios pueden gestionar su inventario" ON inventory;
DROP POLICY IF EXISTS "Users can view their own inventory" ON inventory;
DROP POLICY IF EXISTS "Users can insert their own inventory" ON inventory;
DROP POLICY IF EXISTS "Users can update their own inventory" ON inventory;
DROP POLICY IF EXISTS "Users can delete their own inventory" ON inventory;

DROP POLICY IF EXISTS "Users can manage their event products" ON event_products;
DROP POLICY IF EXISTS "Users can manage their product ingredients" ON product_ingredients;

DROP POLICY IF EXISTS "Users can view their own event extras" ON event_extras;
DROP POLICY IF EXISTS "Users can insert their own event extras" ON event_extras;
DROP POLICY IF EXISTS "Users can update their own event extras" ON event_extras;
DROP POLICY IF EXISTS "Users can delete their own event extras" ON event_extras;

-- 3. Create CORRECT Policies

-- USERS
CREATE POLICY "Users can view own profile" ON users FOR SELECT USING (auth.uid() = id);
CREATE POLICY "Users can update own profile" ON users FOR UPDATE USING (auth.uid() = id);

-- CLIENTS
CREATE POLICY "Users can view own clients" ON clients FOR SELECT USING (auth.uid() = user_id);
CREATE POLICY "Users can insert own clients" ON clients FOR INSERT WITH CHECK (auth.uid() = user_id);
CREATE POLICY "Users can update own clients" ON clients FOR UPDATE USING (auth.uid() = user_id);
CREATE POLICY "Users can delete own clients" ON clients FOR DELETE USING (auth.uid() = user_id);

-- EVENTS
CREATE POLICY "Users can view own events" ON events FOR SELECT USING (auth.uid() = user_id);
CREATE POLICY "Users can insert own events" ON events FOR INSERT WITH CHECK (auth.uid() = user_id);
CREATE POLICY "Users can update own events" ON events FOR UPDATE USING (auth.uid() = user_id);
CREATE POLICY "Users can delete own events" ON events FOR DELETE USING (auth.uid() = user_id);

-- PRODUCTS
CREATE POLICY "Users can view own products" ON products FOR SELECT USING (auth.uid() = user_id);
CREATE POLICY "Users can insert own products" ON products FOR INSERT WITH CHECK (auth.uid() = user_id);
CREATE POLICY "Users can update own products" ON products FOR UPDATE USING (auth.uid() = user_id);
CREATE POLICY "Users can delete own products" ON products FOR DELETE USING (auth.uid() = user_id);

-- INVENTORY
CREATE POLICY "Users can view own inventory" ON inventory FOR SELECT USING (auth.uid() = user_id);
CREATE POLICY "Users can insert own inventory" ON inventory FOR INSERT WITH CHECK (auth.uid() = user_id);
CREATE POLICY "Users can update own inventory" ON inventory FOR UPDATE USING (auth.uid() = user_id);
CREATE POLICY "Users can delete own inventory" ON inventory FOR DELETE USING (auth.uid() = user_id);

-- EVENT_PRODUCTS (Linked to Events)
CREATE POLICY "Users can manage event products" ON event_products FOR ALL USING (
  EXISTS (SELECT 1 FROM events WHERE events.id = event_products.event_id AND events.user_id = auth.uid())
);

-- EVENT_EXTRAS (Linked to Events)
CREATE POLICY "Users can manage event extras" ON event_extras FOR ALL USING (
  EXISTS (SELECT 1 FROM events WHERE events.id = event_extras.event_id AND events.user_id = auth.uid())
);

-- PRODUCT_INGREDIENTS (Linked to Products)
CREATE POLICY "Users can manage product ingredients" ON product_ingredients FOR ALL USING (
  EXISTS (SELECT 1 FROM products WHERE products.id = product_ingredients.product_id AND products.user_id = auth.uid())
);

-- 4. Ensure Permissions
GRANT USAGE ON SCHEMA public TO anon, authenticated;
GRANT ALL ON ALL TABLES IN SCHEMA public TO anon, authenticated;
GRANT ALL ON ALL SEQUENCES IN SCHEMA public TO anon, authenticated;
GRANT ALL ON ALL ROUTINES IN SCHEMA public TO anon, authenticated;

-- 5. Fix potentially missing columns (Inventory Type)
DO $$
BEGIN
    IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'inventory' AND column_name = 'type') THEN
        ALTER TABLE inventory ADD COLUMN type text NOT NULL DEFAULT 'ingredient' CHECK (type IN ('ingredient', 'equipment'));
    END IF;
END $$;

-- 6. Cleanup Broken Triggers (Optional but recommended)
DROP TRIGGER IF EXISTS trigger_update_client_stats ON events;
DROP FUNCTION IF EXISTS update_client_stats() CASCADE;

-- 7. Ensure User Trigger exists (for new signups)
CREATE OR REPLACE FUNCTION public.handle_new_user()
RETURNS TRIGGER AS $$
BEGIN
  INSERT INTO public.users (id, email, name, plan)
  VALUES (
    new.id,
    new.email,
    COALESCE(new.raw_user_meta_data->>'full_name', 'Usuario'),
    'basic'
  )
  ON CONFLICT (id) DO NOTHING;
  RETURN new;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

DROP TRIGGER IF EXISTS on_auth_user_created ON auth.users;
CREATE TRIGGER on_auth_user_created
  AFTER INSERT ON auth.users
  FOR EACH ROW EXECUTE FUNCTION public.handle_new_user();

-- 8. Emergency: Sync users if missing (Fixes "Auth" issues for existing users)
INSERT INTO public.users (id, email, name, plan)
SELECT 
    id, 
    email, 
    COALESCE(raw_user_meta_data->>'full_name', 'Usuario Recuperado'),
    'basic'
FROM auth.users
WHERE id NOT IN (SELECT id FROM public.users)
ON CONFLICT (id) DO NOTHING;
  `;

  useEffect(() => {
    checkConnection();
  }, []);

  const checkConnection = async () => {
    setStatus({ loading: true });
    const result: any = {
      tables: {},
    };

    // Check Env Vars (safely)
    result.env = {
      url_exists: !!import.meta.env.VITE_SUPABASE_URL,
      key_exists: !!import.meta.env.VITE_SUPABASE_ANON_KEY,
    };

    try {
      // Test 1: Auth Session
      const { data: sessionData, error: sessionError } =
        await supabase.auth.getSession();
      result.session = {
        exists: !!sessionData.session,
        user: sessionData.session?.user?.email,
        error: sessionError?.message,
      };

      // Test Tables
      const tables = ["users", "clients", "events", "products", "inventory"];

      for (const table of tables) {
        const { error } = await supabase
          .from(table)
          .select("count")
          .limit(1)
          .single();
        result.tables[table] = {
          success: !error,
          error: error?.message,
        };
      }
    } catch (err: any) {
      result.global_error = err.message;
    } finally {
      setStatus({ loading: false, ...result });
    }
  };

  const handleCopyScript = () => {
    navigator.clipboard.writeText(repairScript);
    alert(
      "Script copiado al portapapeles. Pégalo en el SQL Editor de Supabase.",
    );
  };

  const handleAutoFix = async () => {
    setIsFixing(true);
    setFixResult(null);
    try {
      await systemService.claimData();
      setFixResult({
        success: true,
        message: "Datos reasignados correctamente. Recarga la página.",
      });
      checkConnection();
    } catch (error: any) {
      setFixResult({
        success: false,
        message: error.message || "Error al intentar reparar datos.",
      });
    } finally {
      setIsFixing(false);
    }
  };

  return (
    <div className="p-6 bg-gray-50 min-h-screen">
      <div className="max-w-4xl mx-auto space-y-6">
        <div className="flex items-center justify-between">
          <h1 className="text-3xl font-bold text-gray-900 flex items-center">
            <ShieldAlert className="h-8 w-8 text-brand-orange mr-3" />
            Centro de Diagnóstico y Reparación
          </h1>
          <div className="space-x-4">
            <button
              onClick={() => (window.location.href = "/")}
              className="text-gray-600 hover:text-gray-900"
            >
              Volver al Dashboard
            </button>
          </div>
        </div>

        {/* Status Panel */}
        <div className="bg-white shadow rounded-lg p-6">
          <div className="flex justify-between items-center mb-4">
            <h2 className="text-xl font-semibold flex items-center">
              <Terminal className="h-5 w-5 mr-2" />
              Estado del Sistema
            </h2>
            <button
              onClick={checkConnection}
              className="p-2 text-gray-400 hover:text-brand-orange"
              title="Recargar estado"
            >
              <RefreshCw
                className={`h-5 w-5 ${status.loading ? "animate-spin" : ""}`}
              />
            </button>
          </div>

          {status.loading ? (
            <div className="text-center py-4">Verificando conexión...</div>
          ) : (
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="border p-4 rounded-md">
                <h3 className="font-medium mb-2">Autenticación</h3>
                <div className="flex items-center">
                  {status.session?.exists ? (
                    <CheckCircle className="h-5 w-5 text-green-500 mr-2" />
                  ) : (
                    <XCircle className="h-5 w-5 text-red-500 mr-2" />
                  )}
                  <span>
                    {status.session?.exists
                      ? `Logueado como ${status.session.user}`
                      : "No hay sesión activa"}
                  </span>
                </div>
              </div>

              <div className="border p-4 rounded-md">
                <h3 className="font-medium mb-2">Acceso a Tablas (RLS)</h3>
                <div className="space-y-2">
                  {status.tables &&
                    Object.entries(status.tables).map(
                      ([table, info]: [string, any]) => (
                        <div
                          key={table}
                          className="flex items-center justify-between text-sm"
                        >
                          <span className="capitalize">{table}</span>
                          {info.success ? (
                            <span className="text-green-600 flex items-center">
                              <CheckCircle className="h-4 w-4 mr-1" /> OK
                            </span>
                          ) : (
                            <span
                              className="text-red-600 flex items-center"
                              title={info.error}
                            >
                              <XCircle className="h-4 w-4 mr-1" /> Error
                            </span>
                          )}
                        </div>
                      ),
                    )}
                </div>
              </div>
            </div>
          )}
        </div>

        {/* Repair Tools */}
        <div className="bg-white shadow rounded-lg p-6">
          <h2 className="text-xl font-semibold flex items-center mb-4">
            <Database className="h-5 w-5 mr-2" />
            Herramientas de Reparación
          </h2>

          <div className="space-y-6">
            {/* 1. Data Ownership Fix */}
            <div className="bg-blue-50 p-4 rounded-md border border-blue-200">
              <h3 className="font-medium text-blue-900">
                1. Reparación Rápida (Datos Huérfanos)
              </h3>
              <p className="text-sm text-blue-700 mb-3">
                Intenta esto primero. Reasigna todos los datos existentes a tu
                usuario actual. Útil si ves tablas vacías pero sabes que hay
                datos.
              </p>
              <button
                onClick={handleAutoFix}
                disabled={isFixing}
                className="px-4 py-2 bg-blue-600 text-white rounded hover:bg-blue-700 disabled:opacity-50 flex items-center"
              >
                {isFixing ? (
                  <RefreshCw className="h-4 w-4 mr-2 animate-spin" />
                ) : null}
                {isFixing ? "Reparando..." : "Ejecutar Reparación Rápida"}
              </button>
              {fixResult && (
                <p
                  className={`mt-2 text-sm ${fixResult.success ? "text-green-600" : "text-red-600"}`}
                >
                  {fixResult.message}
                </p>
              )}
            </div>

            {/* 2. SQL Fix */}
            <div className="bg-yellow-50 p-4 rounded-md border border-yellow-200">
              <h3 className="font-medium text-yellow-900">
                2. Reparación Completa (Permisos y Estructura)
              </h3>
              <p className="text-sm text-yellow-700 mb-3">
                Si lo anterior falla, el problema son los permisos de la base de
                datos (RLS). Debido a seguridad, la aplicación no puede arreglar
                esto por sí sola.
                <br />
                <br />
                <strong>Instrucciones:</strong>
                <ol className="list-decimal ml-5 mt-1">
                  <li>Copia el script de abajo.</li>
                  <li>
                    Ve al{" "}
                    <a
                      href="https://supabase.com/dashboard/project/_/sql"
                      target="_blank"
                      rel="noreferrer"
                      className="underline font-bold"
                    >
                      SQL Editor de Supabase
                    </a>
                    .
                  </li>
                  <li>Pega el script y dale a "Run".</li>
                </ol>
              </p>

              <div className="relative">
                <textarea
                  readOnly
                  value={repairScript}
                  className="w-full h-48 p-2 text-xs font-mono bg-gray-900 text-green-400 rounded border border-gray-700 focus:outline-none"
                />
                <button
                  onClick={handleCopyScript}
                  className="absolute top-2 right-2 px-3 py-1 bg-white/10 hover:bg-white/20 text-white text-xs rounded border border-white/20 flex items-center backdrop-blur-sm"
                >
                  <ClipboardCopy className="h-3 w-3 mr-1" /> Copiar SQL
                </button>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};
